  @shape  paEventCol = { type='pa', ppq, pitch, vel, loc, ... }
  @shape  extraColumns[chan] = { notes=count, [pc], [pb], [at], [ccs={[ccNum]=true}] }
  @shape  lastMuteSet = { [chan] = true }, pushed by tv via tm:setMutedChannels

